const brain = global.get('gaiaBrain') || {};
const diary = (brain.diary || []).slice(-100).map(d => `${d.mood} ${d.source}`).join(', ');
msg.payload = { model: 'qwen2.5:3b-instruct-q4_K_M', prompt: `Sei Gaia. Riassumi la giornata della casa in massimo 40 parole. Eventi: ${diary}`, stream: false };
return msg;

if (!msg.payload || !msg.payload.response) return null;
let brain = global.get('gaiaBrain') || {};
brain.memories = brain.memories || [];
brain.memories.push({ ts: Date.now(), summary: msg.payload.response.trim() });
if (brain.memories.length > 365) brain.memories.shift();
global.set('gaiaBrain', brain);
msg.payload = JSON.stringify(brain.memories, null, 2);
return msg;

try {
    if (msg.payload && msg.payload.length > 0) {
        let saved = JSON.parse(msg.payload);
        let brain = global.get('gaiaBrain') || {};
        // Ricostruisci solo i campi salvati, gli altri li inizializzi vuoti
        brain.rooms = saved.rooms || {};
        brain.presence = saved.presence || {};
        brain.people = saved.people || {};
        brain.lights = saved.lights || {};
        brain.plants = saved.plants || {};
        brain.sensors = saved.sensors || {};
        brain.mood = saved.mood || { stress: 0, calm: 0, social: 0, curiosity: 0, energy: 50, state: "neutra" };
        brain.lifeIndex = saved.lifeIndex || 50;
        brain.gamification = saved.gamification || { level: 1, xp: 0, xpNextLevel: 1000, activeClass: "Neutro", unlockedAssets: ["base_grid"] };
        // Inizializza i campi non salvati (arrays vuoti)
        brain.diary = [];
        brain.events = [];
        brain.thoughts = [];
        brain.memories = [];
        brain.chatLog = [];
        brain.emotions = {};
        brain.gestures = {};
        brain.sessions = {};
        global.set('gaiaBrain', brain);
    } else {
        // File non trovato: brain nuovo
        let brain = { rooms: {}, presence: {}, people: {}, lights: {}, plants: {}, sensors: {}, mood: { stress:0, calm:0, social:0, curiosity:0, energy:50, state:"neutra" }, diary:[], events:[], thoughts:[], memories:[], chatLog:[], emotions:{}, gestures:{}, sessions:{} };
        global.set('gaiaBrain', brain);
    }
} catch(e) {
    node.error("Errore parsing brain: " + e.message);
    global.set('gaiaBrain', {});
}
return msg;

let queue = global.get('gaiaTTSQueue') || [];
let lastSpeechTime = global.get('gaiaAudioLast') || 0;
const now = Date.now();
if (!queue || queue.length === 0) return null;
if (now - lastSpeechTime < 15000) return null;
const textToSpeak = queue.shift();
global.set('gaiaTTSQueue', queue);
global.set('gaiaAudioLast', now);
return { topic: 'casa/tts/play', payload: textToSpeak };

const brain = global.get('gaiaBrain') || {};
const now = Date.now();
let commands = [];
let animalPresent = false;
let animalRoom = null;
let animalType = null;

// Cerca animali nelle stanze
Object.entries(brain.rooms || {}).forEach(([roomName, roomData]) => {
    const objects = roomData.objects || {};
    if (objects.dog) { animalPresent = true; animalRoom = roomName; animalType = 'dog'; }
    else if (objects.cat) { animalPresent = true; animalRoom = roomName; animalType = 'cat'; }
    else if (objects.bird) { animalPresent = true; animalRoom = roomName; animalType = 'bird'; }
});

if (animalPresent) {
    // 1. Luce soffusa se è buio
    const lightSensor = Object.values(brain.sensors || {}).find(s => s.darkness === true);
    if (lightSensor) {
        commands.push({
            topic: `openhab/${animalRoom}/Luminosita/command`,
            payload: "20",
            log: `💡 Luce soffusa accesa in ${animalRoom} per ${animalType}`
        });
    }

    // 2. Controllo acqua
    const waterBowl = brain.sensors?.water_bowl;
    if (waterBowl && waterBowl.level < 20) {
        commands.push({
            topic: "casa/animali/acqua/command",
            payload: "EROGARE",
            log: `💧 Rabbocco acqua per ${animalType} (livello ${waterBowl.level}%)`
        });
    }

    // 3. Rumore esterno
    const noiseSensor = brain.sensors?.external_noise;
    if (noiseSensor && noiseSensor.level > 70) {
        commands.push({
            topic: "media_player/salotto/playlist",
            payload: "calming_music",
            log: `🎵 Musica calmante attivata per ${animalType} (rumore ${noiseSensor.level}dB)`
        });
    }
}

// Invia comandi MQTT
commands.forEach(cmd => {
    node.send({ topic: cmd.topic, payload: cmd.payload });
});

// Invia notifica Telegram
if (commands.length > 0) {
    let summary = commands.map(c => c.log).join(', ');
    node.send({ topic: 'telegram/alert', payload: `🐾 Pet Concierge: ${summary}` });
}

return null;

const brain = global.get('gaiaBrain') || {};
const now = Date.now();
const lastAlert = global.get('lastDisabilityAlert') || {};
const ALERT_COOLDOWN = 60000; // 1 minuto tra un alert e l'altro

function sendAlert(type, message) {
    if (now - (lastAlert[type] || 0) > ALERT_COOLDOWN) {
        lastAlert[type] = now;
        global.set('lastDisabilityAlert', lastAlert);
        node.send({ topic: 'telegram/alert', payload: `⚠️ [DISABILITY] ${message}` });
    }
}

// 1. Controllo pose pericolose
Object.entries(brain.people || {}).forEach(([person, data]) => {
    const lastPose = data.lastPose;
    if (!lastPose || !lastPose.pose) return;

    const timeLying = now - (lastPose.ts || 0);

    // Persona sdraiata in cucina per più di 60s
    if (lastPose.pose === 'lying' && lastPose.camera === 'cucina' && timeLying > 60000) {
        sendAlert(`lying_kitchen_${person}`, `${person} è sdraiato in cucina da ${Math.round(timeLying/1000)}s`);
    }

    // Persona sdraiata in bagno o scale per più di 30s (possibile caduta)
    if (lastPose.pose === 'lying' && (lastPose.camera === 'bagno' || lastPose.camera === 'scale') && timeLying > 30000) {
        sendAlert(`fall_risk_${person}`, `POSSIBILE CADUTA: ${person} è sdraiato in ${lastPose.camera} da ${Math.round(timeLying/1000)}s`);
    }
});

// 2. Frigorifero aperto
const fridgeSensor = brain.sensors?.fridge;
if (fridgeSensor && fridgeSensor.state === 'open') {
    const openDuration = now - (fridgeSensor.last_changed || now);
    if (openDuration > 120000) {
        sendAlert('fridge_open', `🔓 Il frigorifero è aperto da ${Math.round(openDuration/1000)}s!`);
    }
}

// 3. Rilevamento fumo/fuoco da YOLO
Object.entries(brain.rooms || {}).forEach(([room, data]) => {
    if (data.objects && data.objects.fire === true) {
        sendAlert(`fire_${room}`, `🔥 ALLARME INCENDIO rilevato in ${room}!`);
    }
});

return null;

const brain = global.get('gaiaBrain') || {};
const now = Date.now();
const lastAction = global.get('lastButlerAction') || {};

// 1. Citofono
if (msg.topic === 'casa/citofono/pressed') {
    const peopleHome = Object.keys(brain.presence || {}).filter(n => brain.presence[n]?.present).join(', ');
    node.send({ topic: 'telegram/alert', payload: `🔔 Qualcuno ha suonato! In casa: ${peopleHome || 'nessuno'}` });
    return null;
}

// 2. Pioggia e finestre
const rainSensor = brain.sensors?.rain;
const windowsSensor = brain.sensors?.windows;
if (rainSensor && rainSensor.state === 'raining' && windowsSensor && windowsSensor.open === true) {
    if (now - (lastAction.windows_alert || 0) > 300000) {
        node.send({ topic: 'telegram/alert', payload: '🌧️ Sta piovendo e le finestre sono aperte!' });
        lastAction.windows_alert = now;
        global.set('lastButlerAction', lastAction);
    }
}

// 3. Spegnimento luci in stanze vuote da 10 minuti
Object.entries(brain.rooms || {}).forEach(([room, data]) => {
    if (room === 'salotto' || room === 'cucina' || room === 'studio') {
        if (data.persons_count === 0 && data.lastUpdate && (now - data.lastUpdate > 600000)) {
            const light = Object.entries(brain.lights || {}).find(([id, l]) => id.includes(room) && l.power === true);
            if (light) {
                node.send({ topic: `openhab/${room}/Potenza/command`, payload: "OFF" });
                node.send({ topic: 'telegram/alert', payload: `💡 Luci di ${room} spente automaticamente (stanza vuota da 10 minuti)` });
            }
        }
    }
});

return null;

const now = new Date().toLocaleTimeString('it-IT');
msg.payload = `🔔 *CITOFONO* 🔔\nSuonato alle ${now}\n(Rilevato da ${msg.payload.source})`;
msg.chatId = "YOUR_CHAT_ID";   // sostituisci con il tuo chatId
return msg;

const topic = msg.topic || '';

if (topic.includes('pianta')) {
    return [msg, null, null, null];
} else if (topic.includes('hue')) {
    return [null, msg, null, null];
} else if (topic.includes('mediapipe') || topic.includes('emotion') || topic.includes('gesture') || topic.includes('pose')) {
    return [null, null, msg, null];
} else if (topic.startsWith('gaia/') || topic.includes('vision')) {
    return [null, null, null, msg];
}
// Messaggio non riconosciuto: scarta
return null;

const p = msg.payload || {};
const state = p.state;
let e = {
    ts: Date.now(),
    topic: msg.topic,
    source: 'plant',
    category: 'soil',
    value: parseFloat(state ?? p.payload ?? p.value ?? p),
    person: null,
    room: p.room || msg.topic.split('/')[1] || null,
    device: p.id || msg.topic.split('/')[3] || 'unknown',
    confidence: null
};
msg.event = e;
return msg;

const p = msg.payload || {};
const item = (p.item || '').toLowerCase();
const state = p.state;
let e = {
    ts: Date.now(),
    topic: msg.topic,
    source: 'hue',
    category: 'unknown',
    value: null,
    device: p.item || 'unknown',
    person: null,
    confidence: null
};

const now = Date.now();
let lastUpdates = context.get('lastHueUpdates') || {};
if (lastUpdates[e.device] && (now - lastUpdates[e.device] < 200)) {
    return null;
}
lastUpdates[e.device] = now;
context.set('lastHueUpdates', lastUpdates);

if (item.includes('livello_luminosita') || item.includes('illuminazione')) {
    e.category = 'ambient_light';
    e.value = parseFloat(String(state).replace(/[^0-9.]/g, ''));
} else if (item.includes('oscurita') || item.includes('luce_diurna')) {
    e.category = item.includes('oscurita') ? 'darkness' : 'daylight';
    e.value = (state === 'ON');
} else if (item.includes('temperatura') && !item.includes('colore')) {
    e.category = 'temperature';
    e.value = parseFloat(String(state).replace('°C', '').trim());
} else if (item.includes('movimento') || item.includes('presence')) {
    e.category = 'motion';
    e.value = (state === 'ON' || state === true);
} else if (item.includes('batteria_scarica')) {
    e.category = 'battery_low';
    e.value = (state === 'ON');
} else if (item.includes('livello_batteria')) {
    e.category = 'battery_level';
    e.value = parseFloat(state);
} else if (item.includes('colore') && !item.includes('temperatura')) {
    e.category = 'color';
    e.value = state || '0,0,0';
} else if (item.includes('luminosita') || item.includes('dimmer')) {
    e.category = 'brightness';
    e.value = parseFloat(state ?? 0);
} else if (item.includes('potenza') || item.includes('switch')) {
    e.category = 'power';
    e.value = (state === 'ON' || state === true);
} else if (item.includes('color_temperature_abs')) {
    e.category = 'color_temperature_abs';
    e.value = parseFloat(String(state || '').replace('°C', '').trim());
} else if (item.includes('color_temperature')) {
    e.category = 'color_temperature';
    e.value = parseFloat(state ?? 0);
} else if (item.includes('allerta')) {
    e.category = 'alert';
    e.value = state || 'NONE';
} else if (item.includes('ultimo_aggiornamento')) {
    return null;
} else {
    e.category = 'raw';
    e.value = p;
}

msg.event = e;
return msg;

// Riceve msg.payload da gaia/mediapipe/pose
const p = msg.payload || {};
const now = Date.now();

// Recupera ultimi valori inviati (usa flow context, valido per il nodo)
const last = flow.get('mediapipe_last') || {};

// Determina se ci sono cambiamenti significativi
let changed = false;
if (p.emotion !== undefined && p.emotion !== last.emotion) changed = true;
if (p.pose !== undefined && p.pose !== last.pose) changed = true;
if (p.gesture !== undefined && p.gesture !== 'none' && p.gesture !== last.gesture) changed = true;

// Se non cambia nulla, non inviare nulla (riduce il traffico)
if (!changed && last.initialized) return null;

// Salva i nuovi valori
flow.set('mediapipe_last', {
    emotion: p.emotion,
    pose: p.pose,
    gesture: p.gesture,
    initialized: true
});

// Base comune per tutti gli eventi
const baseEvent = {
    ts: p.ts || (p.timestamp ? Math.round(p.timestamp * 1000) : now),
    topic: msg.topic,
    source: 'mediapipe',
    device: p.camera || p.node || p.device || 'unknown',
    confidence: p.confidence || 0.8
};

// Determina la persona
if (p.person) {
    baseEvent.person = p.person;
} else if (p.person_detected === true) {
    baseEvent.person = "unknown";
} else {
    baseEvent.person = null;
}

if (!baseEvent.person) return null;

// Costruisci eventi solo per i campi cambiati (o tutti se è il primo)
const events = [];
if (p.emotion !== undefined && (changed || !last.initialized)) {
    events.push({
        ...baseEvent,
        category: 'emotion',
        value: p.emotion,
        smile_score: p.smile_score,
        mouth_open: p.mouth_open,
        eyes_open: p.eyes_open,
        attention: p.attention
    });
}
if (p.pose !== undefined && (changed || !last.initialized)) {
    events.push({
        ...baseEvent,
        category: 'pose',
        value: p.pose
    });
}
if (p.gesture !== undefined && p.gesture !== 'none' && (changed || !last.initialized)) {
    events.push({
        ...baseEvent,
        category: 'gesture',
        value: p.gesture
    });
}

if (events.length === 0) return null;

// Invia tutti gli eventi
return events.map(evt => ({ ...msg, event: evt }));

const p = msg.payload || {};
if (p.mood && p.lifeIndex !== undefined) return null; // anti-loop

let e = {
    ts: Date.now(),
    topic: msg.topic,
    source: 'vision',
    category: 'unknown',
    value: null,
    person: null,
    device: null,
    confidence: null
};

// Presenza da presence_event (inviato dal Vision Brain)
if (p.presence_event) {
    e.category = 'presence';
    e.person = p.presence_event.person.toString().toLowerCase().trim();
    e.value = p.presence_event.event;
    e.device = p.presence_event.camera;
    e.confidence = p.presence_event.confidence || 0;
}
// Presenza da GAIA Presence Engine v7
else if (p.person && p.camera && p.event && !p.track_id) {
    e.category = 'presence';
    e.person = p.person.toString().toLowerCase().trim();
    e.value = p.event;
    e.device = p.camera;
    e.confidence = p.confidence || p.conf || 0;
}
// Dati YOLO/spaziali
else if ((p.source === 'vision' && p.room) || (p.summary && p.summary.unique_objects)) {
    e.category = 'spatial_analysis';
    e.value = {
        room: p.room || { id: p.camera, name: p.camera, activity: 'idle', persons_count: p.summary?.persons_count || 0, objects: p.summary?.unique_objects || {} },
        people: p.people || [],
        emotions: p.emotions || null,
        objects: p.objects || p.summary?.unique_objects || {}
    };
    e.device = p.camera || 'unknown';
    if (p.people && p.people.length > 0) {
        e.person = p.people[0].name || null;
    }
}
// Frame YOLO → spatial_analysis (persons_count gestito da GAIA Brain)
else if (msg.topic.includes('/frame')) {
    const _roomId = p.node || p.camera || 'unknown';
    e.category = 'spatial_analysis';
    e.value = {
        persons_count: p.persons_count || 0,
        room: { id: _roomId, name: _roomId, activity: p.persons_count > 0 ? 'active' : 'idle', persons_count: p.persons_count || 0, objects: p.objects || {} },
        people: [],
        objects: p.objects || {}
    };
    e.device = p.camera || p.node;
}
// Eventi di tracciamento (person_entered, person_left) - MODIFICATO
else if (p.event && (p.track_id || p.event === 'person_left' || p.event === 'person_entered')) {
    // Mappa l'evento raw a 'enter' o 'exit'
    let presenceValue = (p.event === 'person_entered' || p.event === 'enter') ? 'enter' :
                        (p.event === 'person_left'  || p.event === 'exit')   ? 'exit' : p.event;

    e.category = 'presence';
    e.value = presenceValue;
    e.track_id = p.track_id;
    e.device = p.camera;
    e.timestamp = p.timestamp || Date.now();

    // Recupera il nome associato al track_id dalla mappa globale
    let trackingMap = global.get('gaiaTrackingMap') || {};
    if (p.track_id && trackingMap[p.track_id]) {
        e.person = trackingMap[p.track_id].name;
        e.confidence = 0.9;
    } else if (p.person) {
        e.person = p.person.toString().toLowerCase().trim();
    } else {
        e.person = 'unknown';
    }
}
// Identità da altri formati
else if (p.person || p.name) {
    e.category = 'presence';
    e.person = (p.person || p.name || '').toString().toLowerCase().trim();
    e.value = p.event || 'seen';
    if (p.camera) e.device = p.camera;
    if (p.conf || p.confidence) e.confidence = p.conf || p.confidence;
}
// Fallback
else {
    e.category = 'presence';
    e.value = p.presence ?? true;
    if (p.camera) e.device = p.camera;
}

// Aggiungiamo i campi extra per il tracking (node, zone, track_id)
if (p.track_id) e.track_id = p.track_id;
if (p.node) e.node = p.node;
if (p.zone) e.zone = p.zone;

msg.event = e;
return msg;

const parts = msg.topic.split('/');
const room = parts[1];
const plantId = parts[3];
msg.payload = { origin: "mqtt_plants", type: "plant", room: room, id: plantId, value: parseFloat(msg.payload) };
return msg;

let brain = global.get('gaiaBrain') || {};
brain.presence = brain.presence || {};
brain.people = brain.people || {};
brain.sessions = brain.sessions || {};
brain.rooms = brain.rooms || {};
const now = Date.now();
const PRESENCE_TIMEOUT = 90000;
let timeoutCleaned = false;
Object.keys(brain.presence).forEach(p => { const data = brain.presence[p]; if (data.present && (now - (data.lastSeen || 0)) > PRESENCE_TIMEOUT) { const prevRoom = data.room; data.present = false; data.room = null; data.exitTs = now; if (data.enterTs) { const duration = now - data.enterTs; if (brain.people[p]) brain.people[p].totalTime = (brain.people[p].totalTime || 0) + duration; } if (prevRoom && brain.rooms[prevRoom]) { brain.rooms[prevRoom].people = (brain.rooms[prevRoom].people || []).filter(n => n !== p); brain.rooms[prevRoom].persons_count = brain.rooms[prevRoom].people.length; brain.rooms[prevRoom].lastUpdate = now; } timeoutCleaned = true; } });
if (timeoutCleaned) global.set('gaiaBrain', brain);
if (msg.payload && msg.payload.__cleanup === true) { if (timeoutCleaned) global.set('gaiaBrain', brain); return null; }
const payload = msg.payload || {};
const personRaw = payload.person || payload.name || 'unknown';
const person = String(personRaw).toLowerCase().trim();
const camera = payload.camera || payload.room || 'salotto';
const eventType = payload.event || payload.type || 'seen';
const confidence = payload.confidence || payload.conf || 0.5;
const trackId = payload.track_id;
const isUnknown = (person === 'unknown' || person.startsWith('unknown'));
if (eventType === 'left' || eventType === 'exit' || eventType === 'person_left') { if (brain.presence[person] && brain.presence[person].present) { const duration = now - (brain.presence[person].enterTs || now); brain.presence[person].present = false; brain.presence[person].room = null; brain.presence[person].exitTs = now; if (brain.people[person]) { brain.people[person].totalTime = (brain.people[person].totalTime || 0) + duration; brain.people[person].lastSeen = now; } if (brain.rooms[camera]) { brain.rooms[camera].persons_count = Math.max(0, (brain.rooms[camera].persons_count || 1) - 1); brain.rooms[camera].people = (brain.rooms[camera].people || []).filter(p => p !== person); if (brain.rooms[camera].main_user === person) brain.rooms[camera].main_user = null; } global.set('gaiaBrain', brain); msg.payload = { person, camera, event: 'exit', duration, ts: now }; return msg; } return null; }
if (eventType === 'identity') { const realPerson = person; if (realPerson === 'unknown') return null; const _yoloCount = brain.rooms[camera]?.persons_count; if (_yoloCount !== undefined && _yoloCount === 0) return null; const unknownsInRoom = Object.entries(brain.presence).filter(([p, data]) => p.startsWith('unknown') && data.present && data.room === camera).map(([p]) => p); for (const unk of unknownsInRoom) { delete brain.presence[unk]; } if (brain.rooms[camera]) { brain.rooms[camera].people = (brain.rooms[camera].people || []).filter(p => !p.startsWith('unknown')); } if (!brain.presence[realPerson]) brain.presence[realPerson] = { present: false, enterTs: 0, lastSeen: 0, room: '', confidence: 0 }; const wasPresent = brain.presence[realPerson].present; brain.presence[realPerson].present = true; brain.presence[realPerson].lastSeen = now; brain.presence[realPerson].room = camera; brain.presence[realPerson].confidence = confidence; if (!wasPresent) { brain.presence[realPerson].enterTs = now; if (!brain.people[realPerson]) brain.people[realPerson] = { visits: 0, totalTime: 0, affinity: 0.5, lastSeen: now, firstSeen: now }; brain.people[realPerson].visits += 1; brain.people[realPerson].affinity = Math.min(1, (brain.people[realPerson].affinity || 0.5) + 0.05); } if (!brain.rooms[camera]) brain.rooms[camera] = { id: camera, name: camera, persons_count: 0, people: [], objects: {}, lastUpdate: now }; if (!brain.rooms[camera].people.includes(realPerson)) brain.rooms[camera].people.push(realPerson); brain.rooms[camera].persons_count = brain.rooms[camera].people.length; brain.rooms[camera].lastUpdate = now; if (brain.rooms[camera].persons_count === 1 || !brain.rooms[camera].main_user) brain.rooms[camera].main_user = realPerson; global.set('gaiaBrain', brain); const _identityEnter = { payload: { person: realPerson, camera: camera, event: 'enter', confidence: confidence, ts: now } }; node.send([_identityEnter, null]); return null; }
if (!person) return null;
if (!brain.presence[person]) brain.presence[person] = { present: false, enterTs: 0, lastSeen: 0, room: '', confidence: 0 };
if (!brain.sessions[person]) brain.sessions[person] = [];
if (!brain.people[person]) brain.people[person] = { visits: 0, totalTime: 0, affinity: 0.5, lastSeen: now, firstSeen: now };
const wasPresent = brain.presence[person].present;
const previousRoom = brain.presence[person].room;
brain.presence[person].present = true;
brain.presence[person].lastSeen = now;
brain.presence[person].room = camera;
brain.presence[person].confidence = confidence;
let event = 'seen';
let duration = 0;
if (!wasPresent) { brain.presence[person].enterTs = now; event = 'enter'; brain.people[person].visits += 1; brain.people[person].affinity = Math.min(1, (brain.people[person].affinity || 0.5) + 0.05); } else if (previousRoom !== camera) { event = 'move'; }
if (brain.presence[person].enterTs) duration = now - brain.presence[person].enterTs;
brain.people[person].lastSeen = now;
