// POST /gaia/ota/push
// Body: { type: "mediapipe"|"yolo"|"all", script: "mediapipe_node.py", restart: true }
// Calcola MD5, costruisce URL, pubblica su MQTT
const body = msg.payload || {};
const type    = body.type || 'all';
const restart = body.restart !== false;

const FILE_MAP = {
    mediapipe: [
        { script: 'mediapipe_node.py', service: 'gaia-mediapipe' },
        { script: 'ota.py',            service: 'gaia-mediapipe' },
    ],
    yolo: [
        { script: 'main.py',        service: 'gaia-yolo' },
        { script: 'mqtt_client.py', service: 'gaia-yolo' },
        { script: 'ota.py',         service: 'gaia-yolo', remoteScript: 'ota_yolo.py' },
    ],
};

const PATH_MAP = {
    'mediapipe_node.py': '/media/core/D/pi-mediapipe/mediapipe_node.py',
    'ota.py':            '/media/core/D/pi-mediapipe/ota.py',
    'main.py':           '/media/core/D/pi-yolo/main.py',
    'mqtt_client.py':    '/media/core/D/pi-yolo/mqtt_client.py',
    'ota_yolo.py':       '/media/core/D/pi-yolo/ota.py',
};

const host   = msg.req.hostname || '192.168.1.142';
const port   = 1880;

const targets = type === 'all'
    ? [...(FILE_MAP.mediapipe||[]), ...(FILE_MAP.yolo||[])]
    : (FILE_MAP[type] || []);

if (body.script) {
    // Push file singolo
    const single = targets.find(t => t.script === body.script || t.remoteScript === body.script);
    if (!single) { msg.statusCode = 400; msg.payload = {ok:false,error:'script non trovato'}; return [null, msg]; }
    targets.length = 0; targets.push(single);
}

const commands = [];
for (const t of targets) {
    const localPath = PATH_MAP[t.remoteScript || t.script];
    if (!localPath) continue;
    try {
        const content = fs.readFileSync(localPath);
        const md5 = crypto.createHash('md5').update(content).digest('hex');
        const version = new Date().toISOString().slice(0,16).replace('T','-').replace(':','');
        commands.push({
            script:  t.script,
            url:     `http://${host}:${port}/gaia/ota/${t.remoteScript || t.script}`,
            md5:     md5,
            version: version,
            service: t.service,
            restart: restart,
            type:    type === 'all' ? (t.service.includes('mediapipe') ? 'mediapipe' : 'yolo') : type,
        });
    } catch(e) {
        node.warn(`Errore lettura ${localPath}: ${e.message}`);
    }
}

if (commands.length === 0) {
    msg.statusCode = 400;
    msg.payload = {ok: false, error: 'Nessun file trovato'};
    return [null, msg];
}

msg.otaCommands = commands;
const httpResp = { ...msg, payload: { ok: true, pushing: commands.map(c => c.script), ts: Date.now() } };
return [msg, httpResp];

// Pubblica ogni comando OTA su gaia/ota/broadcast
