        topic: 'gaia/home/lights/' + stanza_target + '/set',
        payload: JSON.stringify({ state: 'OFF', stanza: stanza_target })
    }
]);
return null;

const now = new Date();
const ore = now.getHours();
const min = now.getMinutes().toString().padStart(2,'0');
msg.tts_text = 'Sono le ' + ore + ' e ' + min;
return msg;

const giorni = ['domenica','lunedì','martedì','mercoledì','giovedì','venerdì','sabato'];
const mesi = ['gennaio','febbraio','marzo','aprile','maggio','giugno','luglio','agosto','settembre','ottobre','novembre','dicembre'];
const now = new Date();
msg.tts_text = 'Oggi è ' + giorni[now.getDay()] + ' ' + now.getDate() + ' ' + mesi[now.getMonth()] + ' ' + now.getFullYear();
return msg;

// Legge i dati di presenza salvati dal flow YOLO
const presenza = flow.get('persone_in_casa') || {};
const totale = presenza.totale || 0;
const stanze = presenza.stanze || {};

if (totale === 0) {
    msg.tts_text = 'Non ci sono persone rilevate in casa.';
} else if (totale === 1) {
    msg.tts_text = "C'è una persona in casa.";
} else {
    msg.tts_text = 'Ci sono ' + totale + ' persone in casa.';
}
return msg;

const temp = flow.get('temperatura_casa');
if (temp !== null && temp !== undefined) {
    msg.tts_text = 'La temperatura in casa è di ' + Math.round(temp) + ' gradi.';
} else {
    msg.tts_text = 'Non ho dati di temperatura al momento.';
}
return msg;

const brano = msg.entita.brano || '';
msg.tts_text = brano ? 'Metto ' + brano : 'Avvio la musica.';

node.send([
    msg,
    {
        topic: 'gaia/home/music/play',
        payload: JSON.stringify({ brano: brano, stanza: msg.stanza })
    }
]);
return null;

const { valore, unita } = msg.entita;
if (!valore) {
    msg.tts_text = 'Non ho capito la durata del timer.';
    return msg;
}
const unitaLabel = unita && unita.startsWith('second') ? 'secondi' :
                   unita && unita.startsWith('or')     ? (valore === 1 ? 'ora' : 'ore') :
                   (valore === 1 ? 'minuto' : 'minuti');
msg.tts_text = 'Timer impostato per ' + valore + ' ' + unitaLabel + '.';

// Calcola ms
const ms = unita && unita.startsWith('second') ? valore * 1000 :
           unita && unita.startsWith('or')     ? valore * 3600000 :
           valore * 60000;

const stanza = msg.stanza;
setTimeout(() => {
    node.send([null, {
        topic: 'gaia/voice/tts/' + stanza,
        payload: JSON.stringify({ text: 'Timer scaduto!', stanza: stanza, ts: Date.now() })
    }]);
}, ms);

return [msg, null];

const risposte = [
    'Non ho capito. Puoi ripetere?',
    'Scusa, non ho compreso. Riprova.',
    'Non sono sicura di aver capito. Puoi riformulare?'
];
msg.tts_text = risposte[Math.floor(Math.random() * risposte.length)];
return msg;

msg.topic   = 'gaia/voice/tts/' + msg.stanza;
msg.payload = JSON.stringify({
    text:   msg.tts_text,
    stanza: msg.stanza,
    intent: msg.intent,
    ts:     Date.now()
});
return msg;

const parts = msg.topic.split('/');
const stanza = parts[3];
const stati = flow.get('voice_status') || {};
stati[stanza] = {
    state:  msg.payload.state,
    ts:     msg.payload.ts,
    aggiornato: Date.now()
};
flow.set('voice_status', stati);
return null;

const parts = msg.topic.split('/');
const stanza = parts[3] || 'sconosciuta';
const persone = flow.get('persone_in_casa') || { totale: 0, stanze: {} };

const count = msg.payload.count || 0;
persone.stanze[stanza] = { count, ts: Date.now() };

// Rimuovi stanze non aggiornate da più di 30s
const ora = Date.now();
Object.keys(persone.stanze).forEach(s => {
    if (ora - persone.stanze[s].ts > 30000) delete persone.stanze[s];
});

persone.totale = Object.values(persone.stanze).reduce((a, s) => a + s.count, 0);
flow.set('persone_in_casa', persone);
return null;

// Separa ACTION:JSON dal testo di risposta
let text = (msg.payload && (msg.payload.message || msg.payload.response || '')) || msg.tts_text || '';
let action = null;

// Cerca ACTION:{...} in fondo (anche su riga propria)
const actionRe = /\n?ACTION:\s*(\{[^\n\r]+\})\s*$/m;
const m = text.match(actionRe);
if (m) {
    try { action = JSON.parse(m[1]); } catch(e) { action = null; }
    text = text.replace(actionRe, '').trim();
}

msg.payload = { person: msg.person || 'Gaia', message: text, ts: Date.now() };
msg.tts_text = text;
msg.action = action;

// Out 1 → Prepara TTS (sempre)
// Out 2 → ActionRouter (solo se action)
return [msg, action ? msg : null];

const action = msg.action;
if (!action || !action.tipo) return null;

// Out 1 → HueExecutor (tipo=hue)
// Out 2 → GaiaExpression (tipo=stato)
// Out 3 → (futuro: musica, three.js diretto, ecc.)
if (action.tipo === 'hue') return [msg, null, null];
if (action.tipo === 'stato') return [null, msg, null];
return null;

const action = msg.action || {};

// ── Scene predefinite (brightness 0-100, color_temp in Kelvin, color in HSB "H,S,B") ──
const SCENES = {
    alba:     { brightness: 70, color_temp: 3200 },
    relax:    { brightness: 40, color_temp: 2700 },
    focus:    { brightness: 80, color_temp: 5000 },
    sera:     { brightness: 30, color_temp: 2400 },
    notte:    { brightness: 10, color_temp: 2000 },
    festa:    { brightness: 100, color: '0,100,100' },
    tempesta: { brightness: 50, color: '240,60,55' },
    natura:   { brightness: 65, color: '115,70,65' },
};

// ── Mappa stanza → prefisso OpenHAB (adatta ai tuoi item) ────────────────────
// NOTA: i nomi degli item devono corrispondere a quelli in OpenHAB
// Es: openhab/hue/Salotto_Potenza_Luce/command
const ROOM_PREFIX = {
    salotto:  'Salotto',
    cucina:   'Cucina',
    ingresso: 'Ingresso',
    studio:   'Studio',
    camera:   'Camera',
    bagno:    'Bagno',
};

const stanza = (action.stanza || 'salotto').toLowerCase().trim();
const prefix = ROOM_PREFIX[stanza] || (stanza.charAt(0).toUpperCase() + stanza.slice(1));

function cmd(item, value) {
    node.send({ topic: `openhab/hue/${item}/command`, payload: String(value) });
}

// ── Power on/off ──────────────────────────────────────────────────────────────
if (action.power !== undefined) {
    cmd(`${prefix}_Potenza_Luce`, action.power ? 'ON' : 'OFF');
    if (!action.power) return null;
}

// ── Luminosità diretta ────────────────────────────────────────────────────────
if (action.brightness !== undefined) {
    cmd(`${prefix}_Potenza_Luce`, 'ON');
    cmd(`${prefix}_Luminosita_Luce`, Math.max(0, Math.min(100, Math.round(action.brightness))));
}

// ── Colore per nome o HSB ─────────────────────────────────────────────────────
const COLOR_MAP = {
    rosso:   '0,100,70',
    verde:   '110,80,65',
    blu:     '240,100,60',
    giallo:  '50,100,80',
    arancio: '30,100,75',
    viola:   '290,80,65',
    bianco:  '0,0,100',
    warm:    null,   // gestito sotto come color_temp
    cool:    null,
};
if (action.colore) {
    const c = action.colore.toLowerCase();
    if (c === 'warm') {
        cmd(`${prefix}_Potenza_Luce`, 'ON');
        cmd(`${prefix}_TemperaturaColore_Luce`, 2700);
    } else if (c === 'cool') {
        cmd(`${prefix}_Potenza_Luce`, 'ON');
        cmd(`${prefix}_TemperaturaColore_Luce`, 5000);
    } else {
        const hsb = COLOR_MAP[c] || c;
        cmd(`${prefix}_Potenza_Luce`, 'ON');
        cmd(`${prefix}_Colore_Luce`, hsb);
    }
}

// ── Temperatura colore diretta (Kelvin) ───────────────────────────────────────
if (action.color_temp) {
    cmd(`${prefix}_Potenza_Luce`, 'ON');
    cmd(`${prefix}_TemperaturaColore_Luce`, action.color_temp);
}

// ── Scena predefinita ─────────────────────────────────────────────────────────
if (action.scena) {
    const scene = SCENES[action.scena.toLowerCase()];
    if (scene) {
        cmd(`${prefix}_Potenza_Luce`, 'ON');
        cmd(`${prefix}_Luminosita_Luce`, scene.brightness);
        if (scene.color_temp) cmd(`${prefix}_TemperaturaColore_Luce`, scene.color_temp);
        if (scene.color)      cmd(`${prefix}_Colore_Luce`, scene.color);
    }
}

return null;

const brain = global.get('gaiaBrain') || {};
const mood = brain.mood?.state || 'neutra';

// Mappe umore → scena luci
const MOOD_SCENES = {
    neutra:    { brightness: 60, color_temp: 4000, nome: 'luce naturale bilanciata' },
    calm:      { brightness: 35, color_temp: 2700, nome: 'luce soffusa e calda' },
    social:    { brightness: 80, color_temp: 3000, nome: 'luce vivace e accogliente' },
    stress:    { brightness: 50, color_temp: 3200, nome: 'luce moderata' },
    curiosity: { brightness: 75, color_temp: 5000, nome: 'luce brillante e ispiratrice' },
};

const scene = MOOD_SCENES[mood] || MOOD_SCENES.neutra;

// Aggiorna brain.activeScene (ThreeJS lo legge via gaia/brain/state)
brain.activeScene = { mood, ...scene, ts: Date.now() };
global.set('gaiaBrain', brain);

// Trova stanze abitate (esclude nodi camera/vision)
const ROOM_PREFIX = {
    salotto: 'Salotto', cucina: 'Cucina', ingresso: 'Ingresso',
    studio: 'Studio', camera: 'Camera', bagno: 'Bagno',
};
const activeRooms = Object.keys(brain.rooms || {}).filter(r =>
    !r.includes('cam') && !r.includes('vision') && r !== 'unknown' &&
    (brain.rooms[r]?.persons_count || 0) > 0
);
if (activeRooms.length === 0) activeRooms.push('salotto');

for (const room of activeRooms) {
    const prefix = ROOM_PREFIX[room] || (room.charAt(0).toUpperCase() + room.slice(1));
    node.send({ topic: `openhab/hue/${prefix}_Potenza_Luce/command`, payload: 'ON' });
    node.send({ topic: `openhab/hue/${prefix}_Luminosita_Luce/command`, payload: String(scene.brightness) });
    node.send({ topic: `openhab/hue/${prefix}_TemperaturaColore_Luce/command`, payload: String(scene.color_temp) });
}
return null;

// Applica scena umore → OpenHAB
const brain = global.get('gaiaBrain') || {};
const mood = brain.mood?.state || 'neutra';
const MOOD_SCENES = {
    neutra:    { brightness: 60, color_temp: 4000 },
    calm:      { brightness: 35, color_temp: 2700 },
    social:    { brightness: 80, color_temp: 3000 },
    stress:    { brightness: 50, color_temp: 3200 },
    curiosity: { brightness: 75, color_temp: 5000 },
};
const scene = MOOD_SCENES[mood] || MOOD_SCENES.neutra;
brain.activeScene = { mood, ...scene, ts: Date.now() };
global.set('gaiaBrain', brain);

const ROOM_PREFIX = {
    salotto: 'Salotto', cucina: 'Cucina', ingresso: 'Ingresso',
    studio: 'Studio', camera: 'Camera', bagno: 'Bagno',
};
const activeRooms = Object.keys(brain.rooms || {}).filter(r =>
    !r.includes('cam') && !r.includes('vision') && r !== 'unknown' &&
    (brain.rooms[r]?.persons_count || 0) > 0
);
if (activeRooms.length === 0) return null;

for (const room of activeRooms) {
    const prefix = ROOM_PREFIX[room] || (room.charAt(0).toUpperCase() + room.slice(1));
    node.send({ topic: `openhab/hue/${prefix}_Potenza_Luce/command`, payload: 'ON' });
    node.send({ topic: `openhab/hue/${prefix}_Luminosita_Luce/command`, payload: String(scene.brightness) });
    node.send({ topic: `openhab/hue/${prefix}_TemperaturaColore_Luce/command`, payload: String(scene.color_temp) });
}
